{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyOpx8E+X9NtswX5D2KwcpHc"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"vJr98uYc3Zjl"},"outputs":[],"source":["import pandas as pd\n","\n","# Importing dataset\n","df=pd.read_csv('/content/drive/MyDrive/Healthcare Project/Appointment_data.csv')\n","\n","# No null and duplicate values present in dataset\n","\n","df=df[df['Age']>=0]\n","\n","# Fix the Handicap multi-value discrepancy to align with metadata\n","df['Handcap'] = df['Handcap'].apply(lambda x: 1 if x > 0 else 0)\n","\n","# Standard cleaning steps agreed upon in previous sections\n","df = df.rename(columns={'Hipertension': 'Hypertension', 'Handcap': 'Handicap'})\n","\n","# Parse dates and normalize timestamps\n","df['ScheduledDay']=pd.to_datetime(df['ScheduledDay'])\n","df['AppointmentDay']=pd.to_datetime(df['AppointmentDay']).dt.normalize()\n","\n","# Exact binary encoding for variables (Instead of pd.get_dummies)\n","df['Gender']=df['Gender'].map({'F':0,'M':1})\n","df['No-show']=df['No-show'].map({'No':0,'Yes':1})\n","\n","# Feature engineering: Lead time logic\n","df['WaitingDays'] = (df['AppointmentDay'] - df['ScheduledDay'].dt.normalize()).dt.days\n","\n","# Remove the 5 chronologically impossible rows (Data preservation strategy)\n","df = df[df['WaitingDays'] >= 0]\n","\n","# Extract weekday names to bypass ordinal/ranking numbers bias\n","df['AppointmentDayName'] = df['AppointmentDay'].dt.day_name()"]}]}